    private fun shouldKeepNewlineBetweenColonAndReturnType(
        colonNode: ASTNode,
        whiteSpaceAfterColon: ASTNode,
    ): Boolean {
        if (maxLineLength == MAX_LINE_LENGTH_PROPERTY_OFF) {
            return false
        }
        val containingFileText = colonNode.psi?.containingFile?.text ?: return false
        val colonOffset = colonNode.startOffset
        val colonLineStartOffset = containingFileText.lastIndexOf('\n', colonOffset - 1).let { index ->
            if (index == -1) {
                0
            } else {
                index + 1
            }
        }
        val colonLineEndOffset = containingFileText.indexOf('\n', colonOffset).let { index ->
            if (index == -1) {
                containingFileText.length
            } else {
                index
            }
        }
        val colonLineLength = colonLineEndOffset - colonLineStartOffset
        val returnTypeLineStartOffset = whiteSpaceAfterColon.textRange.endOffset
        val returnTypeLineEndOffset = containingFileText.indexOf('\n', returnTypeLineStartOffset).let { index ->
            if (index == -1) {
                containingFileText.length
            } else {
                index
            }
        }
        val returnTypeLineLength = returnTypeLineEndOffset - returnTypeLineStartOffset
        val lineLengthIfReturnTypePlacedOnSameLine = colonLineLength + 1 + returnTypeLineLength
        return lineLengthIfReturnTypePlacedOnSameLine > maxLineLength
    }
}

