import com.pinterest.ktlint.rule.engine.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionReturnTypeSpacingRuleWithEditorConfigTest {
    private val functionReturnTypeSpacingRuleAssertThat = assertThatRule { FunctionReturnTypeSpacingRule() }

    @Test
    fun `Given a long parameterless function signature that would exceed the max line length when the return type is placed on the same line then do not reformat`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                AndAlsoALongReturnType {
            }
            """.trimIndent()

        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function signature that fits within the max line length even when the return type is placed on the same line then reformat`() {
        val code =
            """
            fun foo():
                String = "some-result"
            """.trimIndent()
        val formattedCode =
            """
            fun foo(): String = "some-result"
            """.trimIndent()

        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 200)
            .hasLintViolation(1, 10, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }
}
"}

